-- Via Travels: bulk insert of 17 verified hotels (bypasses the Flutterwave-gated endpoint)
INSERT INTO hotels (
  name, short_description, long_description, star_rating, property_type, built_year, last_renovation_year, chain_affiliation, street_address, city, state, province, country, postal_code, latitude, longitude, map_url, account_bank, account_number, bank_name, business_mobile, business_email, business_contact, business_contact_mobile, total_rooms, cancellation_policy, payment_options, menu_download_url, sponsored, hotel_status, management_email, management_name
) VALUES
('Kigali Serena Hotel', '5-star luxury hotel in central Kigali (Nyarugenge), near the Belgian Peacekeepers Memorial.', 'Kigali’s leading 5-star hotel, with 148 rooms and 25 suites, an outdoor pool, Maisha Spa, fitness centre and major conference venues; about 10 km from Kigali International Airport.', 5, 'Hotel', 2005, 2020, 'Serena Hotels', 'Boulevard de la Révolution, Nyarugenge', 'Kigali', 'Nyarugenge', 'Kigali City', 'Rwanda', '00000', -1.954, 30.0605, 'https://www.google.com/maps?q=-1.954,30.0605', '040', '0010000000', 'Bank of Kigali', '+250788300000', 'kigalireservations@serena.co.rw', 'Reservations Manager', '+250788400000', 173, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/kigali_serena_hotel.pdf', false, 'active'::hotel_status, 'manager.kigali_serena_hotel@viatravels.test', 'kigali_serena_hotel_manager'),
('Hôtel des Mille Collines', 'Historic 4-star hotel in the Kigali CBD, the real-life “Hotel Rwanda”, built 1973.', 'A Kigali landmark built in 1973, the 4-star Hôtel des Mille Collines has 112 rooms and suites, three restaurants, an outdoor pool and tennis courts in the central business district, about 6 km from the airport.', 4, 'Hotel', 1973, 2021, 'MIKCOR (independent)', '2 KN 6 Avenue, Kiyovu', 'Kigali', 'Nyarugenge', 'Kigali City', 'Rwanda', '00000', -1.9469, 30.0619, 'https://www.google.com/maps?q=-1.9469,30.0619', '115', '0010000137', 'I&M Bank Rwanda', '+250788300131', 'info@millecollines.net', 'Reservations Manager', '+250788400131', 112, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/hotel_des_mille_collines.pdf', false, 'active'::hotel_status, 'manager.hotel_des_mille_collines@viatravels.test', 'hotel_des_mille_collines_manager'),
('Hotel Chez Lando', 'Family-run 4-star hotel in bustling Remera, minutes from Kigali Convention Centre and the airport.', 'A well-known 4-star Kigali hotel in Remera with 103 rooms (bungalow, pavilion, new-block, VIP and a suite), the popular La Fringale restaurant and Chez Lando Grill, free airport shuttle and meeting rooms; about 3 km from the airport.', 4, 'Hotel', 2007, 2022, 'Independent', 'KG 201 St, Airport Road, Remera', 'Kigali', 'Gasabo', 'Kigali City', 'Rwanda', '00000', -1.956, 30.113, 'https://www.google.com/maps?q=-1.956,30.113', '070', '0010000274', 'Equity Bank Rwanda', '+250252589804', 'info@chezlando.com', 'Reservations Manager', '+250252589804', 103, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/hotel_chez_lando.pdf', false, 'active'::hotel_status, 'manager.hotel_chez_lando@viatravels.test', 'hotel_chez_lando_manager'),
('Wilderness Sabyinyo Silverback Lodge', 'Luxury community-owned gorilla-trekking lodge on the edge of Volcanoes NP at Kinigi.', 'Rwanda’s first community-owned lodge (SACOLA), now operated by Wilderness, with 8 stone cottages including suites and a family cottage, about 2.3 km from Volcanoes National Park and a short drive from the Kinigi park headquarters.', 5, 'Lodge', 2008, 2023, 'Wilderness', 'Kinigi, edge of Volcanoes National Park, Musanze', 'Kinigi', 'Musanze', 'Northern Province', 'Rwanda', '00000', -1.435, 29.602, 'https://www.google.com/maps?q=-1.435,29.602', '025', '0010000411', 'BPR Bank Rwanda', '+250788300393', 'info.wilderness_sabyinyo_silverback_lodge@viatravels.test', 'Reservations Manager', '+250788400393', 8, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/wilderness_sabyinyo_silverback_lodge.pdf', false, 'active'::hotel_status, 'manager.wilderness_sabyinyo_silverback_lodge@viatravels.test', 'wilderness_sabyinyo_silverback_lodge_manager'),
('Virunga Lodge', 'Iconic Afro-chic luxury lodge on a ridge overlooking the Twin Lakes and Virunga Volcanoes.', 'Built in 2004 by Praveen Moman (Volcanoes Safaris), Virunga Lodge has twelve hand-built bandas (standard and deluxe) with fireplaces and private terraces, a spa and the Dian Fossey Map Room, about 45–60 minutes from Volcanoes National Park headquarters.', 5, 'Lodge', 2004, 2024, 'Volcanoes Safaris', 'High ridge above Lake Burera & Lake Ruhondo, Burera', 'Burera', 'Burera', 'Northern Province', 'Rwanda', '00000', -1.417, 29.79, 'https://www.google.com/maps?q=-1.417,29.79', '130', '0010000548', 'Ecobank Rwanda', '+250788300524', 'info.virunga_lodge@viatravels.test', 'Reservations Manager', '+250788400524', 12, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/virunga_lodge.pdf', false, 'active'::hotel_status, 'manager.virunga_lodge@viatravels.test', 'virunga_lodge_manager'),
('Mountain Gorilla View Lodge', 'Eco-lodge of 30 stone-and-thatch cottages at Kinigi, on the rim of Volcanoes NP.', 'A 4-star eco-lodge with 30 spacious stone-and-thatch cottages, each with a fireplace, en-suite bathroom and private veranda, about 1 km from Volcanoes National Park and 15 minutes from the Kinigi headquarters.', 4, 'Eco-Lodge', 2010, 2020, '3B Hotels', 'Kinigi, edge of Volcanoes National Park, Musanze', 'Kinigi', 'Musanze', 'Northern Province', 'Rwanda', '00000', -1.45, 29.61, 'https://www.google.com/maps?q=-1.45,29.61', '040', '0010000685', 'Bank of Kigali', '+250788300655', 'info@3bhotels.com', 'Reservations Manager', '+250788400655', 30, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/mountain_gorilla_view_lodge.pdf', false, 'active'::hotel_status, 'manager.mountain_gorilla_view_lodge@viatravels.test', 'mountain_gorilla_view_lodge_manager'),
('Hotel Muhabura', 'Historic budget/mid-range town hotel in Musanze where Dian Fossey once stayed.', 'A long-established Musanze town hotel with 30 rooms and apartments, a restaurant, pool and gardens, opposite the Musanze District headquarters and a convenient base for Volcanoes National Park.', 3, 'Hotel', 2011, 2021, 'Independent', 'Avenue du 5 Juillet, Musanze (Ruhengeri)', 'Musanze', 'Musanze', 'Northern Province', 'Rwanda', '00000', -1.499, 29.634, 'https://www.google.com/maps?q=-1.499,29.634', '115', '0010000822', 'I&M Bank Rwanda', '+250788364774', 'info.hotel_muhabura@viatravels.test', 'Reservations Manager', '+250788364774', 30, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/hotel_muhabura.pdf', false, 'active'::hotel_status, 'manager.hotel_muhabura@viatravels.test', 'hotel_muhabura_manager'),
('La Palme Hotel', 'Small 3-star hotel in Musanze, about 10 km from Volcanoes National Park.', 'A modest 3-star Musanze hotel with 14 furnished rooms including 2 suites, a restaurant with French and Oriental menus and a conference room for up to 50 people, about 10 km from Volcanoes National Park.', 3, 'Hotel', 2012, 2022, 'Independent', 'Musanze town, near Volcanoes National Park', 'Musanze', 'Musanze', 'Northern Province', 'Rwanda', '00000', -1.4995, 29.635, 'https://www.google.com/maps?q=-1.4995,29.635', '070', '0010000959', 'Equity Bank Rwanda', '+250788300917', 'palmehotel02@yahoo.fr', 'Reservations Manager', '+250788400917', 14, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/la_palme_hotel.pdf', false, 'active'::hotel_status, 'manager.la_palme_hotel@viatravels.test', 'la_palme_hotel_manager'),
('Virunga Hotel', 'Mid-range Musanze town hotel near the Musanze Modern Market, base for Volcanoes NP.', 'A mid-range hotel in Muhoza, central Musanze, with 72 guestrooms, free Wi-Fi and cable TV, a short walk from Musanze Modern Market and about 15 km from Volcanoes National Park.', 3, 'Hotel', 2013, 2023, 'Virunga Hotels', 'Muhoza, Musanze (Ruhengeri)', 'Musanze', 'Musanze', 'Northern Province', 'Rwanda', '00000', -1.498, 29.633, 'https://www.google.com/maps?q=-1.498,29.633', '025', '0010001096', 'BPR Bank Rwanda', '+250788301048', 'info@virungahotel.com', 'Reservations Manager', '+250788401048', 72, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/virunga_hotel.pdf', false, 'active'::hotel_status, 'manager.virunga_hotel@viatravels.test', 'virunga_hotel_manager'),
('Kinigi Guesthouse', 'Budget guesthouse at Kinigi, right by the Volcanoes NP trek departure point.', 'A simple guesthouse run by ASOFERWA at Kinigi, beside the Volcanoes National Park headquarters where gorilla and golden-monkey treks begin — one of the closest budget options to the park gate.', 2, 'Guesthouse', 2014, 2024, 'ASOFERWA', 'Kinigi, beside Volcanoes NP headquarters, Musanze', 'Kinigi', 'Musanze', 'Northern Province', 'Rwanda', '00000', -1.433, 29.616, 'https://www.google.com/maps?q=-1.433,29.616', '130', '0010001233', 'Ecobank Rwanda', '+250788301179', 'asoferwa@rwanda1.com', 'Reservations Manager', '+250788401179', 15, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/kinigi_guesthouse.pdf', false, 'active'::hotel_status, 'manager.kinigi_guesthouse@viatravels.test', 'kinigi_guesthouse_manager'),
('Lake Kivu Serena Hotel', '4-star lakefront resort hotel on Lake Kivu in Gisenyi (formerly the Kivu Sun).', 'Formerly the Kivu Sun, the 4-star Lake Kivu Serena Hotel sits on a private palm-lined beach in Gisenyi with about 66 rooms plus family rooms and suites, a pool, spa, tennis and a conference centre; about 160 km from Kigali. (P.O. Box 226 Gisenyi.)', 4, 'Hotel', 2015, 2020, 'Serena Hotels', 'Shores of Lake Kivu, Gisenyi (Rubavu)', 'Gisenyi', 'Rubavu', 'Western Province', 'Rwanda', '00000', -1.685, 29.256, 'https://www.google.com/maps?q=-1.685,29.256', '040', '0010001370', 'Bank of Kigali', '+250788200430', 'info.lake_kivu_serena_hotel@viatravels.test', 'Reservations Manager', '+250788200430', 72, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/lake_kivu_serena_hotel.pdf', false, 'active'::hotel_status, 'manager.lake_kivu_serena_hotel@viatravels.test', 'lake_kivu_serena_hotel_manager'),
('Moriah Hill Resort', 'Lakeside resort on a peninsula on Lake Kivu, about 1 km from Karongi town.', 'A family-run lakeside resort set on a peninsula on Lake Kivu about 1 km from Karongi (Kibuye) town, with a private beach, restaurant overlooking the water, sauna and boat trips; rooms have AC, TV and lake views.', 3, 'Resort', 2016, 2021, 'Independent', 'Lakeshore peninsula, Karongi (Kibuye)', 'Kibuye', 'Karongi', 'Western Province', 'Rwanda', '00000', -2.061, 29.347, 'https://www.google.com/maps?q=-2.061,29.347', '115', '0010001507', 'I&M Bank Rwanda', '+250788301441', 'moriah.hill@yahoo.com', 'Reservations Manager', '+250788401441', 22, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/moriah_hill_resort.pdf', false, 'active'::hotel_status, 'manager.moriah_hill_resort@viatravels.test', 'moriah_hill_resort_manager'),
('Home Saint Jean', 'Budget church-run guesthouse perched above Lake Kivu in Kibuye, with lake views.', 'A church-run budget guesthouse on a hill overlooking Lake Kivu in Karongi (Kibuye), offering simple rooms and dormitories with excellent lake views, an affordable restaurant and swimming access, next to the Home Saint Jean genocide memorial.', 2, 'Guesthouse', 2005, 2022, 'Catholic Church (independent)', 'Hilltop above Lake Kivu, Karongi (Kibuye)', 'Kibuye', 'Karongi', 'Western Province', 'Rwanda', '00000', -2.06, 29.348, 'https://www.google.com/maps?q=-2.06,29.348', '070', '0010001644', 'Equity Bank Rwanda', '+250788301572', 'info.home_saint_jean@viatravels.test', 'Reservations Manager', '+250788401572', 18, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/home_saint_jean.pdf', false, 'active'::hotel_status, 'manager.home_saint_jean@viatravels.test', 'home_saint_jean_manager'),
('Hotel Centre Bethanie', 'Budget lakeshore guesthouse directly on Lake Kivu in Kibuye, known for its restaurant terrace.', 'A simple guesthouse set directly on the Lake Kivu shore in Karongi (Kibuye), popular for its well-kept restaurant terrace and lake views and used as a base for boat trips on the lake.', 2, 'Guesthouse', 2006, 2023, 'Independent', 'Lakeshore, Karongi (Kibuye)', 'Kibuye', 'Karongi', 'Western Province', 'Rwanda', '00000', -2.059, 29.346, 'https://www.google.com/maps?q=-2.059,29.346', '025', '0010001781', 'BPR Bank Rwanda', '+250788301703', 'info.hotel_centre_bethanie@viatravels.test', 'Reservations Manager', '+250788401703', 16, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/hotel_centre_bethanie.pdf', false, 'active'::hotel_status, 'manager.hotel_centre_bethanie@viatravels.test', 'hotel_centre_bethanie_manager'),
('Hotel Ibis Huye', 'Landmark town hotel in Huye (Butare) since 1942, near the Ethnographic Museum.', 'A Huye (Butare) landmark operating since 1942, this central mid-range hotel has well-kept gardens, a restaurant regarded as the town’s most reliable and a terrace, about 1.6 km from the Ethnographic Museum. (B.P. 103 Butare.)', 3, 'Hotel', 1942, 2024, 'Independent', 'Main Street, Huye (Butare)', 'Huye', 'Huye', 'Southern Province', 'Rwanda', '00000', -2.597, 29.739, 'https://www.google.com/maps?q=-2.597,29.739', '130', '0010001918', 'Ecobank Rwanda', '+250788301834', 'campionibis@hotmail.com', 'Reservations Manager', '+250788401834', 24, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/hotel_ibis_huye.pdf', false, 'active'::hotel_status, 'manager.hotel_ibis_huye@viatravels.test', 'hotel_ibis_huye_manager'),
('Hotel Faucon', 'Historic main-street hotel in Huye (Butare) with a restaurant and bar.', 'A historic hotel on the main road through Huye (Butare), with a restaurant and a popular bar; a long-standing fixture of the southern heritage circuit near the National Museum.', 3, 'Hotel', 2008, 2020, 'Independent', 'Main Street, Huye (Butare)', 'Huye', 'Huye', 'Southern Province', 'Rwanda', '00000', -2.5965, 29.7395, 'https://www.google.com/maps?q=-2.5965,29.7395', '040', '0010002055', 'Bank of Kigali', '+250788301965', 'faucon@yahoo.fr', 'Reservations Manager', '+250788401965', 20, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/hotel_faucon.pdf', false, 'active'::hotel_status, 'manager.hotel_faucon@viatravels.test', 'hotel_faucon_manager'),
('Hotel Credo', 'Mid-range Huye (Butare) hotel with a swimming pool and restaurant.', 'A mid-range hotel on the road toward the University of Rwanda in Huye (Butare), with a swimming pool and restaurant; a comfortable base for the Ethnographic Museum and southern Rwanda.', 3, 'Hotel', 2009, 2021, 'Independent', 'Towards the University, Huye (Butare)', 'Huye', 'Huye', 'Southern Province', 'Rwanda', '00000', -2.6, 29.742, 'https://www.google.com/maps?q=-2.6,29.742', '115', '0010002192', 'I&M Bank Rwanda', '+250788302096', 'credohotel@yahoo.fr', 'Reservations Manager', '+250788402096', 26, 'Free cancellation up to 48 hours before check-in; later cancellations may incur a one-night charge.', ARRAY['Visa','Momo']::payment_options[], 'https://viatravels.example/menus/hotel_credo.pdf', false, 'active'::hotel_status, 'manager.hotel_credo@viatravels.test', 'hotel_credo_manager');
